import Link from "next/link"
import { PrismaClient } from "@prisma/client"
import { ProductCard } from "@/components/product-card"

const prisma = new PrismaClient()

export default async function Home() {
  const categories = await prisma.category.findMany({
    take: 6,
    orderBy: {
      name: 'asc'
    }
  })

  // We fetch top products based on average rating or just random for now
  const products = await prisma.product.findMany({
    take: 6,
    include: {
      reviews: {
        select: {
          overallRating: true
        }
      }
    }
  })

  // Calculate average rating and review count on the fly
  const topProducts = products.map(product => {
    const reviewCount = product.reviews.length
    const averageRating = reviewCount > 0 
      ? product.reviews.reduce((acc, rev) => acc + rev.overallRating, 0) / reviewCount
      : 0

    return {
      ...product,
      reviewCount,
      averageRating
    }
  }).sort((a, b) => b.averageRating - a.averageRating)

  return (
    <div className="flex flex-col gap-16 pb-16">
      {/* Hero Section */}
      <section className="bg-indigo text-paper py-20 px-4 md:px-6 relative overflow-hidden">
        <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-saffron via-transparent to-transparent pointer-events-none"></div>
        <div className="container mx-auto max-w-4xl text-center flex flex-col items-center gap-6 relative z-10">
          <h1 className="font-heading text-4xl md:text-6xl font-black tracking-tight leading-tight">
            Discover Software <br />
            <span className="text-saffron">Built for Bharat</span>
          </h1>
          <p className="text-lg md:text-xl text-paper/80 max-w-2xl font-medium">
            The trusted B2B review platform for Indian enterprises. Find GST-ready, DPDP-compliant tools with authentic peer reviews.
          </p>
          <div className="flex flex-wrap items-center justify-center gap-4 mt-4">
            <Link href="/categories" className="bg-saffron text-indigo font-bold px-8 py-4 rounded-md hover:bg-saffron/90 transition-colors shadow-lg">
              Browse Categories
            </Link>
            <Link href="/for-vendors" className="bg-white/10 text-paper font-semibold px-8 py-4 rounded-md hover:bg-white/20 transition-colors border border-white/20 backdrop-blur-sm">
              Claim Your Profile
            </Link>
          </div>
        </div>
      </section>

      {/* Featured Categories */}
      <section className="container mx-auto px-4 md:px-6">
        <div className="flex items-center justify-between mb-8">
          <h2 className="font-heading text-2xl md:text-3xl font-bold text-ink">Popular Categories</h2>
          <Link href="/categories" className="text-indigo font-medium hover:underline">View all &rarr;</Link>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
          {categories.map(category => (
            <Link 
              key={category.id} 
              href={`/categories/${category.slug}`}
              className="flex flex-col items-center justify-center gap-3 p-6 rounded-xl bg-white border border-indigo/10 shadow-sm hover:border-indigo hover:shadow-md transition-all text-center group"
            >
              <div className="w-12 h-12 rounded-full bg-indigo/5 flex items-center justify-center text-indigo group-hover:bg-indigo group-hover:text-paper transition-colors">
                <span className="font-bold text-lg">{category.name.charAt(0)}</span>
              </div>
              <span className="font-semibold text-sm text-ink">{category.name}</span>
            </Link>
          ))}
        </div>
      </section>

      {/* Trending Products */}
      <section className="container mx-auto px-4 md:px-6">
        <div className="flex items-center justify-between mb-8">
          <h2 className="font-heading text-2xl md:text-3xl font-bold text-ink">Trending Products</h2>
          <Link href="/products" className="text-indigo font-medium hover:underline">View all &rarr;</Link>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {topProducts.map(product => (
            <ProductCard 
              key={product.id}
              id={product.id}
              name={product.name}
              slug={product.slug}
              logoUrl={product.logoUrl}
              description={product.description}
              pricingText={product.pricingText}
              averageRating={product.averageRating}
              reviewCount={product.reviewCount}
            />
          ))}
        </div>
      </section>
    </div>
  )
}
